//! Integration tests for as_proxy functionality

use fastmcp_server::{Server, ServerBuilder};
use fastmcp_transport::MemoryTransport;

#[tokio::test]
async fn test_as_proxy_discovers_tools() {
    // Create external server
    let external = ServerBuilder::new("external", "1.0")
        .tool(echo_tool())
        .tool(add_tool())
        .build();

    // Create transport pair
    let (client_transport, server_transport) = MemoryTransport::pair();

    // Run external server
    tokio::spawn(async move {
        external.run(server_transport).await.unwrap();
    });

    // Create main server with proxy
    let main = ServerBuilder::new("main", "1.0")
        .as_proxy("ext", client_transport)
        .await
        .unwrap()
        .build();

    // List tools should include proxied tools
    let tools = main.list_tools().await.unwrap();
    assert!(tools.tools.iter().any(|t| t.name == "ext/echo"));
    assert!(tools.tools.iter().any(|t| t.name == "ext/add"));
}

#[tokio::test]
async fn test_as_proxy_calls_forwarded() {
    let external = ServerBuilder::new("external", "1.0")
        .tool(echo_tool())
        .build();

    let (client_transport, server_transport) = MemoryTransport::pair();

    tokio::spawn(async move {
        external.run(server_transport).await.unwrap();
    });

    let main = ServerBuilder::new("main", "1.0")
        .as_proxy("ext", client_transport)
        .await
        .unwrap()
        .build();

    // Call proxied tool
    let result = main.call_tool("ext/echo", json!({"message": "hello"})).await.unwrap();
    assert_eq!(result.content[0].text(), Some("hello"));
}

#[tokio::test]
async fn test_as_proxy_handles_disconnect() {
    let external = ServerBuilder::new("external", "1.0")
        .tool(echo_tool())
        .build();

    let (client_transport, server_transport) = MemoryTransport::pair();

    let server_handle = tokio::spawn(async move {
        external.run(server_transport).await.unwrap();
    });

    let main = ServerBuilder::new("main", "1.0")
        .as_proxy("ext", client_transport)
        .await
        .unwrap()
        .build();

    // Kill external server
    server_handle.abort();

    // Call should fail gracefully
    let result = main.call_tool("ext/echo", json!({"message": "hello"})).await;
    assert!(result.is_err());
}

#[tokio::test]
async fn test_multiple_proxies() {
    // Create two external servers
    let db = ServerBuilder::new("db", "1.0").tool(query_tool()).build();
    let api = ServerBuilder::new("api", "1.0").tool(fetch_tool()).build();

    let (db_client, db_server) = MemoryTransport::pair();
    let (api_client, api_server) = MemoryTransport::pair();

